import React, { useState, useEffect } from "react";
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  PieChart, Pie, Cell, LineChart, Line, ScatterChart, Scatter, ZAxis
} from 'recharts';
import "./BatchAnalysis.css";

function BatchAnalysis({ onFileChange, onAnalyze, loading, results, selectedFile }) {
  const [filteredData, setFilteredData] = useState(null);
  const [filters, setFilters] = useState({
    riskLevels: [],
    tenureRange: [0, 200],
    ordersRange: [0, 100]
  });

  const handleFileSelect = (e) => {
    if (e.target.files.length > 0) {
      onFileChange(e);
      setFilteredData(null);
      setFilters({
        riskLevels: [],
        tenureRange: [0, 200],
        ordersRange: [0, 100]
      });
    }
  };

  // Apply filters when results change
  useEffect(() => {
    if (results && results.predictions) {
      applyFilters(results.predictions, filters);
    }
  }, [results, filters]);

  const applyFilters = (data, filterSettings) => {
    let filtered = data;
    
    if (filterSettings.riskLevels.length > 0) {
      filtered = filtered.filter(item => 
        filterSettings.riskLevels.includes(item.Risk_Level)
      );
    }
    
    filtered = filtered.filter(item => 
      item.Tenure >= filterSettings.tenureRange[0] && 
      item.Tenure <= filterSettings.tenureRange[1] &&
      item.OrderCount >= filterSettings.ordersRange[0] && 
      item.OrderCount <= filterSettings.ordersRange[1]
    );
    
    setFilteredData(filtered);
  };

  const handleFilterChange = (filterType, value) => {
    const newFilters = { ...filters, [filterType]: value };
    setFilters(newFilters);
  };

  const renderRiskDistributionChart = () => {
    if (!filteredData) return null;
    
    const riskCounts = filteredData.reduce((acc, item) => {
      acc[item.Risk_Level] = (acc[item.Risk_Level] || 0) + 1;
      return acc;
    }, {});

    const chartData = Object.entries(riskCounts).map(([risk, count]) => ({
      risk,
      count,
      fill: risk.includes('High') ? '#ef4444' : risk.includes('Moderate') ? '#f97316' : '#34d399'
    }));

    return (
      <div className="chart-container">
        <h4>Customer Distribution by Risk Level</h4>
        <ResponsiveContainer width="100%" height={300}>
          <BarChart data={chartData}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="risk" />
            <YAxis />
            <Tooltip />
            <Bar dataKey="count" fill="#8884d8">
              {chartData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={entry.fill} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    );
  };

  const renderProbabilityDistribution = () => {
    if (!filteredData) return null;

    const bins = Array.from({ length: 10 }, (_, i) => ({
      range: `${(i * 10)}-${(i + 1) * 10}%`,
      count: 0
    }));

    filteredData.forEach(item => {
      const binIndex = Math.floor(item.Churn_Probability * 10);
      if (binIndex < 10) {
        bins[binIndex].count++;
      }
    });

    return (
      <div className="chart-container">
        <h4>Distribution of Churn Probabilities</h4>
        <ResponsiveContainer width="100%" height={300}>
          <BarChart data={bins}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="range" />
            <YAxis />
            <Tooltip />
            <Bar dataKey="count" fill="#06b6d4" />
          </BarChart>
        </ResponsiveContainer>
      </div>
    );
  };

  const renderFeatureAnalysis = () => {
    if (!filteredData) return null;

    const features = ['Tenure', 'CashbackAmount', 'DaySinceLastOrder', 'SatisfactionScore', 'OrderCount'];
    const availableFeatures = features.filter(f => filteredData[0] && filteredData[0][f] !== undefined);

    return availableFeatures.slice(0, 3).map(feature => {
      const featureData = filteredData
        .filter(item => !isNaN(item[feature]))
        .map(item => ({
          riskLevel: item.Risk_Level,
          value: parseFloat(item[feature])
        }));

      const riskGroups = {};
      featureData.forEach(item => {
        if (!riskGroups[item.riskLevel]) {
          riskGroups[item.riskLevel] = [];
        }
        riskGroups[item.riskLevel].push(item.value);
      });

      const boxPlotData = Object.entries(riskGroups).map(([risk, values]) => {
        const sorted = values.sort((a, b) => a - b);
        const q1 = sorted[Math.floor(sorted.length * 0.25)];
        const median = sorted[Math.floor(sorted.length * 0.5)];
        const q3 = sorted[Math.floor(sorted.length * 0.75)];
        const min = sorted[0];
        const max = sorted[sorted.length - 1];

        return { risk, min, q1, median, q3, max };
      });

      return (
        <div key={feature} className="chart-container">
          <h4>{feature} Distribution by Risk Level</h4>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={boxPlotData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="risk" />
              <YAxis />
              <Tooltip />
              <Bar dataKey="median" fill="#8884d8" />
            </BarChart>
          </ResponsiveContainer>
        </div>
      );
    });
  };

  const renderValueRiskAnalysis = () => {
    if (!filteredData) return null;

    const scatterData = filteredData
      .filter(item => !isNaN(item.CashbackAmount) && !isNaN(item.OrderCount) && !isNaN(item.Churn_Probability))
      .map(item => ({
        customerValue: (item.CashbackAmount || 0) * (item.OrderCount || 1),
        churnProbability: item.Churn_Probability * 100,
        riskLevel: item.Risk_Level,
        orderCount: item.OrderCount || 1
      }));

    return (
      <div className="chart-container">
        <h4>Churn Risk vs Customer Value</h4>
        <ResponsiveContainer width="100%" height={400}>
          <ScatterChart data={scatterData}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="customerValue" name="Customer Value" />
            <YAxis dataKey="churnProbability" name="Churn Probability %" />
            <ZAxis dataKey="orderCount" range={[50, 500]} name="Order Count" />
            <Tooltip cursor={{ strokeDasharray: '3 3' }} />
            <Scatter name="Customers" data={scatterData} fill="#8884d8">
              {scatterData.map((entry, index) => (
                <Cell 
                  key={`cell-${index}`} 
                  fill={
                    entry.riskLevel.includes('High') ? '#ef4444' : 
                    entry.riskLevel.includes('Moderate') ? '#f97316' : '#34d399'
                  } 
                />
              ))}
            </Scatter>
          </ScatterChart>
        </ResponsiveContainer>
      </div>
    );
  };

  const renderSegmentCard = (segmentData, riskLevel, color, icon, label) => {
    if (!segmentData || segmentData.length === 0) return null;

    const count = segmentData.length;
    const avgChurn = (segmentData.reduce((sum, item) => sum + item.Churn_Probability, 0) / count) * 100;
    const avgRecency = segmentData.reduce((sum, item) => sum + (item.DaySinceLastOrder || 0), 0) / count;
    const avgOrders = segmentData.reduce((sum, item) => sum + (item.OrderCount || 0), 0) / count;

    let recommendations = [];
    if (riskLevel === 'High') {
      recommendations = [
        "Initiate executive-level 1:1 outreach immediately.",
        "Offer premium, non-monetary incentives (e.g., free upgrade).",
        "Analyze last 3 interactions/orders to resolve the root cause."
      ];
    } else if (riskLevel === 'Medium') {
      recommendations = [
        "Deploy a high-value, exclusive discount/bonus within 7 days.",
        "Focus on removing friction points (payments, app experience).",
        "Send personalized product recommendations to drive visits."
      ];
    } else {
      recommendations = [
        "Enroll in a tiered loyalty program or highlight existing status.",
        "Use non-sales content (tips, guides) to prevent slow drift.",
        "Offer incentives for referrals or reviews (Advocacy & Upsell)."
      ];
    }

    const csvData = segmentData.map(item => ({
      ...item,
      Churn_Probability: (item.Churn_Probability * 100).toFixed(2) + '%'
    }));

    const csvContent = [
      Object.keys(csvData[0]).join(','),
      ...csvData.map(row => Object.values(row).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);

    return (
      <div className="segment-card">
        <div className="segment-header">
          <div className="segment-title" style={{ color }}>
            {icon} {label} ({count} Customers)
          </div>
          <span className="segment-priority">Priority: {riskLevel}</span>
        </div>
        
        <div className="segment-metrics">
          <div className="metric">
            <div className="metric-label">Avg. Churn Prob.</div>
            <div className="metric-value">{avgChurn.toFixed(1)}%</div>
          </div>
          <div className="metric">
            <div className="metric-label">Avg. Days Inactive</div>
            <div className="metric-value">{avgRecency.toFixed(1)} days</div>
          </div>
          <div className="metric">
            <div className="metric-label">Avg. Orders</div>
            <div className="metric-value">{avgOrders.toFixed(1)}</div>
          </div>
        </div>

        <div className="segment-recommendations">
          <div className="recommendation-title" style={{ color }}>
            {riskLevel === 'High' ? 'CRITICAL INTERVENTION' : 
             riskLevel === 'Medium' ? 'PROACTIVE ENGAGEMENT' : 'LOYALTY MAXIMIZATION'}
          </div>
          <ul>
            {recommendations.map((rec, index) => (
              <li key={index}>{rec}</li>
            ))}
          </ul>
        </div>

        <a 
          href={url} 
          download={`${riskLevel.toLowerCase()}_risk_customers.csv`}
          className="download-btn"
        >
          Download {riskLevel} Segment CSV
        </a>
      </div>
    );
  };

  const renderExecutiveScorecard = () => {
    if (!filteredData) return null;

    const totalCustomers = filteredData.length;
    const highRiskCount = filteredData.filter(item => item.Risk_Level.includes('High')).length;
    const avgOrderValue = 850;
    const totalPotentialLoss = filteredData.reduce((sum, item) => 
      sum + (item.Churn_Probability * avgOrderValue * (item.OrderCount || 1)), 0
    );
    const retentionBudget = totalPotentialLoss * 0.15;
    const roi = retentionBudget > 0 ? totalPotentialLoss / retentionBudget : 0;

    const highRiskData = filteredData.filter(item => item.Risk_Level.includes('High'));
    let primaryConcern = 'Unknown';
    if (highRiskData.length > 0) {
      const concerns = {
        'DaySinceLastOrder': highRiskData.reduce((sum, item) => sum + (item.DaySinceLastOrder || 0), 0) / highRiskData.length,
        'SatisfactionScore': highRiskData.reduce((sum, item) => sum + (item.SatisfactionScore || 0), 0) / highRiskData.length,
        'Complain': highRiskData.reduce((sum, item) => sum + (item.Complain || 0), 0) / highRiskData.length
      };
      primaryConcern = Object.keys(concerns).reduce((a, b) => concerns[a] > concerns[b] ? a : b);
      primaryConcern = primaryConcern.replace(/([A-Z])/g, ' $1').trim();
    }

    return (
      <div className="executive-scorecard">
        <h3>Portfolio Summary ({totalCustomers} Customers Selected)</h3>
        
        <div className="kpi-grid">
          <div className="kpi-card">
            <div className="kpi-title">Total Customers (Filtered)</div>
            <div className="kpi-value">{totalCustomers.toLocaleString()}</div>
          </div>
          
          <div className="kpi-card">
            <div className="kpi-title">High-Risk %</div>
            <div className="kpi-value">{((highRiskCount / totalCustomers) * 100).toFixed(1)}%</div>
          </div>
          
          <div className="kpi-card">
            <div className="kpi-title">Potential Revenue Loss</div>
            <div className="kpi-value">₹{(totalPotentialLoss / 100000).toFixed(1)} Lakh</div>
          </div>
          
          <div className="kpi-card">
            <div className="kpi-title">ROI on Retention Investment</div>
            <div className="kpi-value">{roi.toFixed(1)}x</div>
          </div>
        </div>

        {highRiskCount > 0 && (
          <div className="critical-insights">
            <h4>CRITICAL INSIGHTS (P1)</h4>
            <p>
              The {highRiskCount} high-risk customers account for a potential loss of 
              <strong> ₹{totalPotentialLoss.toLocaleString()}</strong>. The primary driver 
              for this segment's churn risk is currently: <strong>{primaryConcern}</strong>.
            </p>
          </div>
        )}
      </div>
    );
  };

  const renderResults = () => {
    if (!results || !filteredData) return null;

    const displayData = filteredData || results.predictions || [];

    // Group data by risk level for segmentation
    const highRiskData = displayData.filter(item => item.Risk_Level.includes('High'));
    const mediumRiskData = displayData.filter(item => item.Risk_Level.includes('Moderate'));
    const lowRiskData = displayData.filter(item => item.Risk_Level.includes('Low'));

    const [activeTab, setActiveTab] = useState('scorecard');

    return (
      <div className="batch-results">
        <h3>📊 Batch Analysis Results</h3>
        
        {/* Filters */}
        <div className="filters-section">
          <h4>Filter Customer Segments</h4>
          <div className="filter-grid">
            <div className="filter-group">
              <label>Risk Level</label>
              <select 
                multiple
                value={filters.riskLevels}
                onChange={(e) => {
                  const selected = Array.from(e.target.selectedOptions, option => option.value);
                  handleFilterChange('riskLevels', selected);
                }}
                className="multi-select"
              >
                <option value="P1: High Risk (>70%)">High Risk</option>
                <option value="P2: Moderate Risk (31-70%)">Moderate Risk</option>
                <option value="P3: Low Risk (<=30%)">Low Risk</option>
              </select>
            </div>
            
            <div className="filter-group">
              <label>Tenure Range (Months)</label>
              <div className="range-inputs">
                <input 
                  type="number" 
                  value={filters.tenureRange[0]}
                  onChange={(e) => handleFilterChange('tenureRange', [parseInt(e.target.value), filters.tenureRange[1]])}
                  min="0"
                  max="200"
                />
                <span>to</span>
                <input 
                  type="number" 
                  value={filters.tenureRange[1]}
                  onChange={(e) => handleFilterChange('tenureRange', [filters.tenureRange[0], parseInt(e.target.value)])}
                  min="0"
                  max="200"
                />
              </div>
            </div>
            
            <div className="filter-group">
              <label>Order Count Range</label>
              <div className="range-inputs">
                <input 
                  type="number" 
                  value={filters.ordersRange[0]}
                  onChange={(e) => handleFilterChange('ordersRange', [parseInt(e.target.value), filters.ordersRange[1]])}
                  min="0"
                  max="100"
                />
                <span>to</span>
                <input 
                  type="number" 
                  value={filters.ordersRange[1]}
                  onChange={(e) => handleFilterChange('ordersRange', [filters.ordersRange[0], parseInt(e.target.value)])}
                  min="0"
                  max="100"
                />
              </div>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="results-tabs">
          <button 
            className={`tab-button ${activeTab === 'scorecard' ? 'active' : ''}`}
            onClick={() => setActiveTab('scorecard')}
          >
            ⭐ Executive Scorecard
          </button>
          <button 
            className={`tab-button ${activeTab === 'segmentation' ? 'active' : ''}`}
            onClick={() => setActiveTab('segmentation')}
          >
            💡 Actionable Segmentation
          </button>
          <button 
            className={`tab-button ${activeTab === 'analytics' ? 'active' : ''}`}
            onClick={() => setActiveTab('analytics')}
          >
            📈 Detailed Analytics
          </button>
        </div>

        {/* Tab Content */}
        <div className="tab-content">
          {activeTab === 'scorecard' && renderExecutiveScorecard()}
          
          {activeTab === 'segmentation' && (
            <div className="segmentation-view">
              <h3>Actionable Customer Segmentation</h3>
              <div className="segmentation-grid">
                <div className="segment-column">
                  {renderSegmentCard(highRiskData, 'High', '#ef4444', '🚨', 'P1: High Risk (>70%)')}
                </div>
                <div className="segment-column">
                  {renderSegmentCard(mediumRiskData, 'Medium', '#f97316', '⚠️', 'P2: Moderate Risk (31-70%)')}
                </div>
                <div className="segment-column">
                  {renderSegmentCard(lowRiskData, 'Low', '#34d399', '✅', 'P3: Low Risk (<=30%)')}
                </div>
              </div>
              
              <div className="download-all-section">
                <button className="download-all-btn">
                  📥 Download All Filtered Results CSV (for CRM import)
                </button>
              </div>
            </div>
          )}
          
          {activeTab === 'analytics' && (
            <div className="analytics-view">
              <h3>Visual Analytics</h3>
              
              <div className="charts-grid">
                <div className="chart-row">
                  {renderRiskDistributionChart()}
                </div>
                
                <div className="chart-row">
                  {renderProbabilityDistribution()}
                </div>
                
                <div className="chart-row">
                  {renderFeatureAnalysis()}
                </div>
                
                <div className="chart-row">
                  {renderValueRiskAnalysis()}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="batch-analysis">
      <div className="analysis-container">
        <div className="section-card">
          <div className="file-upload-area">
            <input
              type="file"
              accept=".csv"
              onChange={handleFileSelect}
              className="file-input"
              id="batch-file"
            />
            <label htmlFor="batch-file" className="file-label">
              <span className="btn-icon">📎</span>
              Choose CSV File
            </label>
            
            {selectedFile && (
              <div className="file-info">
                <span className="file-success">✅</span>
                <div className="file-details">
                  <strong>{selectedFile.name}</strong>
                  <span>{(selectedFile.size / 1024).toFixed(1)} KB</span>
                </div>
              </div>
            )}
            
            <div className="file-requirements">
              <p><small>Required format: CSV with customer features matching individual analysis fields</small></p>
            </div>
          </div>

          <div className="action-buttons-bottom">
            <button 
              className="action-btn primary" 
              onClick={onAnalyze} 
              disabled={loading || !selectedFile}
            >
              {loading ? (
                <>
                  <div className="spinner"></div>
                  Processing Batch...
                </>
              ) : (
                <>
                  <span className="btn-icon">🚀</span>
                  Analyze Batch
                </>
              )}
            </button>
          </div>
        </div>

        {renderResults()}
      </div>
    </div>
  );
}

export default BatchAnalysis;
